code.C++:
#include <iostream>
using namespace std;

int main() {
    string one = "Coding";
    string two = "on";
    string three = "CodeChef";
    string four = one + " " + two + " " + three;
    cout << one + " - " << one.length() << endl;
    cout << two + " - " << two.length() << endl;
    cout << three + " - " << three.length() << endl;
    cout << four + " - " << four.length();
    return 0;
}

